 435	  // support function as second arg
 436	  if (typeof options === 'function') {
 437	    done = options;
 438	    opts = {};
 439	  }
 440	
 441	  if (!opts.root && !isAbsolute(path)) {
 442	    throw new TypeError('path must be absolute or specify root to res.sendFile');
 443	  }
