 445	  // create file stream
 446	  var pathname = encodeURI(path);
 447	  var file = send(req, pathname, opts);
 448	
 449	  // transfer
 450	  sendfile(res, file, opts, function (err) {
 451	    if (done) return done(err);
 452	    if (err && err.code === 'EISDIR') return next();
