/**
 * Handle the error for the layer.
 *
 * @param {Error} error
 * @param {Request} req
 * @param {Response} res
 * @param {function} next
 * @api private
 */

Layer.prototype.handle_error = function handle_error(error, req, res, next) {
  var fn = this.handle;

  if (fn.length !== 4) {
    // not a standard error handler
    return next(error);
  }

  try {
    var ret = fn(error, req, res, next);
    if (ret && typeof ret.then === 'function') {
      // Async handler - guard next() to only be called once
      var called = false;
      ret.then(function () {
        if (!called) {
          called = true;
        }
      }, function (err) {
        if (!called) {
          called = true;
          next(err);
        }
      });
    }
  } catch (err) {
    next(err);
  }
};

