'use strict';

var express = require('./');
var http = require('http');
var assert = require('assert');

// Helper to make HTTP requests
function makeRequest(app, path, headers, callback) {
  var server = http.createServer(app);
  server.listen(0, function () {
    var port = server.address().port;
    var options = {
      hostname: 'localhost',
      port: port,
      path: path,
      method: 'GET',
      headers: headers || {}
    };

    var req = http.request(options, function (res) {
      var body = '';
      res.on('data', function (chunk) {
        body += chunk;
      });
      res.on('end', function () {
        server.close(function () {
          callback(null, res, body);
        });
      });
    });

    req.on('error', function (err) {
      server.close(function () {
        callback(err);
      });
    });

    req.end();
  });
}

// Test 1: CRLF validation in utils
console.log('\n=== Test 1: CRLF validation utility ===');
var containsInvalidHeaderChar = require('./lib/utils').containsInvalidHeaderChar;

// Test literal CRLF
assert.strictEqual(containsInvalidHeaderChar('foo\r'), true, 'Should detect \\r');
assert.strictEqual(containsInvalidHeaderChar('foo\n'), true, 'Should detect \\n');
assert.strictEqual(containsInvalidHeaderChar('foo\r\n'), true, 'Should detect \\r\\n');

// Test escaped CRLF
assert.strictEqual(containsInvalidHeaderChar('foo\\r'), true, 'Should detect escaped \\r');
assert.strictEqual(containsInvalidHeaderChar('foo\\n'), true, 'Should detect escaped \\n');

// Test safe strings
assert.strictEqual(containsInvalidHeaderChar('foo'), false, 'Safe string should pass');
assert.strictEqual(containsInvalidHeaderChar('foo bar'), false, 'Safe string with space should pass');

// Test arrays
assert.strictEqual(containsInvalidHeaderChar(['foo', 'bar']), false, 'Safe array should pass');
assert.strictEqual(containsInvalidHeaderChar(['foo', 'bar\r']), true, 'Array with CRLF should fail');

// Test other types
assert.strictEqual(containsInvalidHeaderChar(123), false, 'Number should pass');
assert.strictEqual(containsInvalidHeaderChar(null), false, 'null should pass');
assert.strictEqual(containsInvalidHeaderChar(undefined), false, 'undefined should pass');
assert.strictEqual(containsInvalidHeaderChar(true), false, 'boolean should pass');

console.log('✓ CRLF validation utility works correctly');

// Test 2: res.set() rejects CRLF
console.log('\n=== Test 2: res.set() CRLF rejection ===');
var app2 = express();
app2.get('/test', function (req, res) {
  try {
    res.set('X-Test', 'value\r\n');
    res.status(500).send('Should have thrown');
  } catch (e) {
    res.status(200).send('Caught: ' + e.message);
  }
});

makeRequest(app2, '/test', {}, function (err, res, body) {
  if (err) {
    console.error('Error:', err);
    process.exit(1);
  }
