Layer.prototype.handle_error = function handle_error(error, req, res, next) {
  var fn = this.handle;

  if (fn.length !== 4) {
    // not a standard error handler
    return next(error);
  }

  // Track if next() was called (synchronously or otherwise)
  var called = false;
  function nextOnce(err) {
    if (called) return;
    called = true;
    next(err);
  }

  try {
    var ret = fn(error, req, res, nextOnce);
    if (ret && typeof ret.then === 'function') {
      // Async handler - guard to only call next once
      ret.then(function () {
        // Handler completed without calling next - nothing to do
      }, function (err) {
        if (!called) {
          called = true;
          next(err);
        }
      });
    }
  } catch (err) {
    nextOnce(err);
  }
};

