exports.containsInvalidHeaderChar = function containsInvalidHeaderChar(value) {
  if (typeof value === 'string') {
    // Check for literal CR or LF characters (char codes 13 and 10)
    // Also check for escaped sequences \r and \n
    return /[\r\n]|\\r|\\n/.test(value);
  }

  if (Array.isArray(value)) {
    for (var i = 0; i < value.length; i++) {
      if (containsInvalidHeaderChar(value[i])) {
        return true;
      }
    }
  }

  // Numbers, booleans, null, undefined are safe
  return false;
};

